INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2461, 217067, 6, 1944, '一句话的分量', '文字一直随着情绪和感慨在指尖跳跃，在耳麦的乐曲中文字变换着怒悲哀喜的旋律，习惯于这样的表达自己，习惯于这样的投入完全自我的世界；感觉与他人无关，与人类无关，只有真实的自己。然而，现实中的现实告诉我，语言和文字可以左右一个人的思想，往往是随便无心说出的一句话，随便让手指轻敲键盘打出的一句文字，已经在自己漠然不知的情况下给别人带来了感触和伤害。也许感觉不是完全属于自己的，应该有一个角落是属于和自己一样的所有同类，所以每说一句话都要考虑对方听过之后的感觉，尽量让自己的语言温暖轻柔的落在每一颗心上，在他人能接受与否的程度上多加一个砝码，善待而没有伤害的砝码。
<br>     每个人都有一个纯真烂漫的童年，有如天使一般的洁白无暇；不知道天有多高，不知道地有多广，幼小的心灵里只有万物的美好。父母的关爱和老师的教导是他们最初的启蒙，每一句肯定和鼓励都可能影响未来的人生，正确的引导和教诲会使其从稚嫩过渡到成熟，让有些原本的平凡意外的亮出一个辉煌的点。一路走来，成长的过程是人生极其重要的开端，也是需要在师长亲人的点化之下完成人生初始阶段的过程。记忆里无数次跌倒，无数次被亲人扶起；和蔼的笑容，慈爱的呵护以及谆谆的教导，都是童年里不能忘却的记忆，也是提醒自己与人为善的灵魂。也许酸甜苦辣的一生里什么都可以丢失，唯有良善是面对红尘的准则。也是一个喜欢敲打文字，喜欢满天满地的去飞，喜欢不高兴的时候让眼睛出汗的女人的准则。
<br>     在物欲横流的新生时代，人们变换着节奏去创造去证明，此一刻彼一刻的换着面孔去演着自己的角色，虽然疲惫至极却无法停滞不前。难得的闲暇之余，轻品茶香，望着流动的浮云，渴望拥有一份温情，拥有一个属于自己的最爱，拥有一个安全栖身的港湾。因此，一句“我爱你”感动了天下无数的痴情男女，虽然知道情感之路也许不会一帆风顺，也许会伤痕累累疼痛一生；但是人们无法克制自己的真情去忽略和抹杀那句爱情的经典“我爱你”。诚然感情的路上有悲有喜，也有不遂人愿的改变，但是每一句誓言和诺言都有着曾经的真实。天不老地不荒，人们追求挚爱的真诚是原始而新潮的，是恒古不变的。
<br>     雨一直是自己的难得知己，默契相知相交如出一人，她的蓝色性格和脱离现实的纯净和这个社会形成了及大的反差。她有一男友从相识那一刻起就对她衷情有增无减，他对她的呵护和关爱超过了任何人，她的每一句话每一点微小的情绪变化都时刻影响着他的生活，她知道他已经把自己当成了生命里的唯一。但是她始终觉得与他有着一层看不见东西阻隔着，她似乎知道是什么，似乎又不知道是什么。一日，他无意说出了前任女友的照片一直保留，而且他们分手已尽十年。仅此一句话让她知道了什么是寒冷，什么是隔在他们中间的那层看不见的东西。她知道他心灵深处有着一份永远都不能割舍的怀念，她恍然明白，当他说起她和他心里的影子有着同一个姓氏的时候所流露的那份怜爱之中，包含着他内心深处的那份不属于自己的深爱。她无法做到不在乎，无法让自己作为他把她当做另一个影子的精神寄托，爱既然不完整，就只有放弃；虽然他爱她。他们之间谁是谁非已无须深究，但是感情是自私的，没有人能够做到洒脱大方。一句话可以开始一段感情，拥有一个完满的结局；一句话也可以结束一段感情，留下一个刻骨铭心的遗憾。
<br>     凡尘之中，尽管人都是一样的高级动物，但是却生活在不同的阶层和不同的环境；因此对生活的感受千差万别，个中滋味只有自己明了。其实，光鲜抑或是平凡的背后都有着自己的负累和烦恼，也许还有着不为人知的悲痛和感伤。对于人生里的坎坷和磨难我们无法改变，对于熟悉和不熟悉的某个人的遭遇和经历我们也许无能为力；但是，一句简单适宜的问候，一句关爱真挚的安慰却可以让他人感觉到其实真情从来就不曾远离自己，人与人之间并非都是利欲熏心自私自利，还有最真最质朴闪着光的东西存在。在给予他人感动和温暖的同时，也给自己增加了一点生活的勇气和动力，因为你已经感觉到还有人需要你，知道事物都是相辅相成的，有美好也有丑恶，因此人生没有绝对完满的人生。当你能以祥和的心态坦然的面对纷繁尘世的时候，你会由衷的感叹说一句“活着真好”。是的，一句话温暖了你我他，世界因为有了你我他才美丽！', '文字一直随着情绪和感慨在指尖跳跃，在耳麦的乐曲中文字变换着怒悲哀喜的旋律，习惯于这样的表达自己，习惯于这样的投入完全自我的世界；感觉与他人无关，与人类无关，只有真实的自己。然而，现实中的现实告诉我，语言和文字可以左右一个人的思想，往往是随便无心说出的一句话，随便让手指轻敲键盘打出的一句文字，已经在自己漠然不知的情况下给别人带来了感触和伤害。也许感觉不是完全属于自己的，应该有一个角落是属于和自己一样的所有同类，所以每说一句话都要考虑对方听过之后的感觉，尽量让自己的语言温暖轻柔的落在每一颗心上，在他人能接受与否的程度上多加一个砝码，善待而没有伤害的砝码。

每个人都有一个纯真烂漫的童年，有如天使一般的洁白无暇；不知道天有多高，不知道地有多广，幼小的心灵里只有万物的美好。父母的关爱和老师的教导是他们最初的启蒙，每一句肯定和鼓励都可能影响未来的人生，正确的引导和教诲会使其从稚嫩过渡到成熟，让有些原本的平凡意外的亮出一个辉煌的点。一路走来，成长的过程是人生极其重要的开端，也是需要在师长亲人的点化之下完成人生初始阶段的过程。记忆里无数次跌倒，无数次被亲人扶起；和蔼的笑容，慈爱的呵护以及谆谆的教导，都是童年里不能忘却的记忆，也是提醒自己与人为善的灵魂。也许酸甜苦辣的一生里什么都可以丢失，唯有良善是面对红尘的准则。也是一个喜欢敲打文字，喜欢满天满地的去飞，喜欢不高兴的时候让眼睛出汗的女人的准则。

在物欲横流的新生时代，人们变换着节奏去创造去证明，此一刻彼一刻的换着面孔去演着自己的角色，虽然疲惫至极却无法停滞不前。难得的闲暇之余，轻品茶香，望着流动的浮云，渴望拥有一份温情，拥有一个属于自己的最爱，拥有一个安全栖身的港湾。因此，一句“我爱你”感动了天下无数的痴情男女，虽然知道情感之路也许不会一帆风顺，也许会伤痕累累疼痛一生；但是人们无法克制自己的真情去忽略和抹杀那句爱情的经典“我爱你”。诚然感情的路上有悲有喜，也有不遂人愿的改变，但是每一句誓言和诺言都有着曾经的真实。天不老地不荒，人们追求挚爱的真诚是原始而新潮的，是恒古不变的。

雨一直是自己的难得知己，默契相知相交如出一人，她的蓝色性格和脱离现实的纯净和这个社会形成了及大的反差。她有一男友从相识那一刻起就对她衷情有增无减，他对她的呵护和关爱超过了任何人，她的每一句话每一点微小的情绪变化都时刻影响着他的生活，她知道他已经把自己当成了生命里的唯一。但是她始终觉得与他有着一层看不见东西阻隔着，她似乎知道是什么，似乎又不知道是什么。一日，他无意说出了前任女友的照片一直保留，而且他们分手已尽十年。仅此一句话让她知道了什么是寒冷，什么是隔在他们中间的那层看不见的东西。她知道他心灵深处有着一份永远都不能割舍的怀念，她恍然明白，当他说起她和他心里的影子有着同一个姓氏的时候所流露的那份怜爱之中，包含着他内心深处的那份不属于自己的深爱。她无法做到不在乎，无法让自己作为他把她当做另一个影子的精神寄托，爱既然不完整，就只有放弃；虽然他爱她。他们之间谁是谁非已无须深究，但是感情是自私的，没有人能够做到洒脱大方。一句话可以开始一段感情，拥有一个完满的结局；一句话也可以结束一段感情，留下一个刻骨铭心的遗憾。

凡尘之中，尽管人都是一样的高级动物，但是却生活在不同的阶层和不同的环境；因此对生活的感受千差万别，个中滋味只有自己明了。其实，光鲜抑或是平凡的背后都有着自己的负累和烦恼，也许还有着不为人知的悲痛和感伤。对于人生里的坎坷和磨难我们无法改变，对于熟悉和不熟悉的某个人的遭遇和经历我们也许无能为力；但是，一句简单适宜的问候，一句关爱真挚的安慰却可以让他人感觉到其实真情从来就不曾远离自己，人与人之间并非都是利欲熏心自私自利，还有最真最质朴闪着光的东西存在。在给予他人感动和温暖的同时，也给自己增加了一点生活的勇气和动力，因为你已经感觉到还有人需要你，知道事物都是相辅相成的，有美好也有丑恶，因此人生没有绝对完满的人生。当你能以祥和的心态坦然的面对纷繁尘世的时候，你会由衷的感叹说一句“活着真好”。是的，一句话温暖了你我他，世界因为有了你我他才美丽！', '因为爱过&nbsp;所以慈悲，因为懂得&nbsp;所以宽容。

熙子', '2003-10-30 22:31:00', 6, '20040103141802_bbsid_217067_board_6_bade7c82b3.html', '20040103141802');
